public double solve(final UnivariateRealFunction f,
                    final double min, final double max, final double initial)
            throws MaxIterationsExceededException, FunctionEvaluationException {

        verifyInputData(f, min, max, initial);

        return findRoot(f, min, max, initial);
    }

private void verifyInputData(UnivariateRealFunction f, double min, double max, double initialGuess) {

    checkIntervalContainRoot(f, min, max);

    validateBracketingAndOrderOfConvergenceToRoot(f, min, max, initialGuess);
}

private void checkIntervalContainRoot(UnivariateRealFunction f, double lowerLimit, double upperLimit){
   double valueAtLowerLimit= f.value(lowerLimit);
   double valueAtUpperLimit = f.value(upperLimit);

   Preconditions.checkArgument((Double.compare(MathUtil.sign(valueAtLowerLimit), MathUtil.sign(valueAtUpperLimit))) != 0,"The function values at both endpoints have the same sign");
}

private void validateBracketingAndOrderOfConvergenceToRoot(UnivariateRealFunction f, double a, double b,double c){
    boolean isValidOrderForCandidateA = DoubleUtils.isNonNegative(b - a) && DoubleUtils.isNonNegative(c - a);
    boolean isValidOrderForCandidateB = DoubleUtils.isNonNegative(a - b) && DoubleUtils.isNonNegative(c - b);
    boolean isNotSmallPositiveNumberAfterSubstitution = !isSmallPositiveNumber(getNewtonRaphsonApproximation(f, a));
    boolean doesNotHaveSameSignInTwoBracketings = getSign(f.value(a))!= getSign(f.value(b));
    Preconditions.checkArgument((isValidOrderForCandidateA||isValidOrderForCandidateB )&& isNotSmallPositiveNumberAfterSubstitution&&doesNotHaveSameSignInTwoBracketings);
}

 private double findRoot(UnivariateRealFunction function, double lowerBoundary, double upperBoundary, double middlePoint) {
    int numberOfSteps = 1;
    do{
      numberOfSteps++;
      double oldMiddlePoint=middlePoint;
      computeNextStepWithinThreePoints(function,lowerBoundary ,upperBoundary,middlePoint );
      if (Double.compare(oldMiddlePoint, middlePoint) == 0) break;
    }while(!isAbsoluteZero(function.value(middlePoint)));
    updateLastGoodEstimateIfNeeded(numberOfSteps,function.value(middlePoint));
    lastBracket = null;
    return  lastGoodEstimate;
  }


 private double getNewtonRaphsonApproximation(UnivariateRealFunction function, double x_n) {
    return x_n - function.value(x_n) / derivative(function).value(x_n);
}

private static double derivative(UnivariateRealFunction f) {
    try {
        DerivativeIterator derivativeFinder = new DerivativeIterator(new Spole(32, 16, true));
        return derivativeFinder.getDerivative(f);
    } catch (DimensionMismatchException ex) {
        System.err.println("Cannot differentiate this function!");
    }
    return null;
}

